import{_ as a,c as s,o as t,ag as d}from"./chunks/framework.B-vhMDQ8.js";const u=JSON.parse('{"title":"Claude Code Setup (macOS)","description":"","frontmatter":{},"headers":[],"relativePath":"notes/tools/claude/setup.md","filePath":"notes/tools/claude/setup.md"}'),o={name:"notes/tools/claude/setup.md"};function i(l,e,c,n,r,h){return t(),s("div",null,[...e[0]||(e[0]=[d(`<h1 id="claude-code-setup-macos" tabindex="-1">Claude Code Setup (macOS) <a class="header-anchor" href="#claude-code-setup-macos" aria-label="Permalink to &quot;Claude Code Setup (macOS)&quot;">​</a></h1><p>npm 安装、代理配置与首次启动。</p><hr><h2 id="_1-环境" tabindex="-1">1. 环境 <a class="header-anchor" href="#_1-环境" aria-label="Permalink to &quot;1. 环境&quot;">​</a></h2><ul><li>macOS；Node.js 18+；<code>npm install -g @anthropic-ai/claude-code</code></li></ul><h2 id="_2-安装与验证" tabindex="-1">2. 安装与验证 <a class="header-anchor" href="#_2-安装与验证" aria-label="Permalink to &quot;2. 安装与验证&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @anthropic-ai/claude-code</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>若 <code>command not found</code>：在 <code>~/.zshrc</code> 加 <code>export PATH=&quot;$(npm config get prefix)/bin:$PATH&quot;</code>，再 <code>source ~/.zshrc</code>。</p><h2 id="_3-代理-无法直连时" tabindex="-1">3. 代理（无法直连时） <a class="header-anchor" href="#_3-代理-无法直连时" aria-label="Permalink to &quot;3. 代理（无法直连时）&quot;">​</a></h2><p>在 <code>~/.zshrc</code> 末尾加（端口改为你的）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">alias</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> claude-proxy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;HTTP_PROXY=http://127.0.0.1:7890 HTTPS_PROXY=http://127.0.0.1:7890 claude&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>执行 <code>source ~/.zshrc</code>。<strong>若配置了代理，启动、登录与日常使用都必须用 <code>claude-proxy</code>，不要用 <code>claude</code>。</strong></p><h2 id="_4-登录" tabindex="-1">4. 登录 <a class="header-anchor" href="#_4-登录" aria-label="Permalink to &quot;4. 登录&quot;">​</a></h2><p>首次运行选登录方式（Claude 订阅 / Console API / 第三方）。若报 403，用 <code>claude-proxy</code> 启动后再 <code>/login</code>。</p><h2 id="_5-后续使用" tabindex="-1">5. 后续使用 <a class="header-anchor" href="#_5-后续使用" aria-label="Permalink to &quot;5. 后续使用&quot;">​</a></h2><ul><li>需代理：<code>claude-proxy</code>；不需代理：<code>claude</code></li><li><code>claude doctor</code>、<code>claude config</code>（需代理时先用 <code>claude-proxy</code> 启动）</li></ul><h2 id="_6-常见问题" tabindex="-1">6. 常见问题 <a class="header-anchor" href="#_6-常见问题" aria-label="Permalink to &quot;6. 常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>处理</th></tr></thead><tbody><tr><td>command not found</td><td>PATH 加 npm global bin，<code>source ~/.zshrc</code></td></tr><tr><td>改完 .zshrc 不生效</td><td>当前终端执行 <code>source ~/.zshrc</code> 或新开终端</td></tr><tr><td>403 / Please run /login</td><td>用 <code>claude-proxy</code> 启动，再 <code>/login</code>；代理环境下必须用 <code>claude-proxy</code></td></tr><tr><td>安装脚本返回 HTML</td><td>地区限制，用 npm 安装</td></tr></tbody></table>`,18)])])}const b=a(o,[["render",i]]);export{u as __pageData,b as default};
